{"script":"if [ ! -f /usr/stock.log ]; then echo "MISSING"; exit 0; fi

echo "HEAD:"; head -n 10 /usr/stock.log

echo "---ANALYSIS---"

awk '
{
  action="";
  action_idx=0;
  for(i=1;i<=NF;i++){
    if(tolower($i)=="buy"||tolower($i)=="sell"){ action=tolower($i); action_idx=i; break; }
  }
  if(action=="") next;
  trader="";
  for(i=action_idx-1;i>=1;i--){
    if($i !~ /^[0-9.]+$/ && tolower($i)!="buy" && tolower($i)!="sell"){ trader=$i; break; }
  }
  if(trader==""){
    for(i=action_idx+1;i<=NF;i++){
      if($i !~ /^[0-9.]+$/ && tolower($i)!="buy" && tolower($i)!="sell"){ trader=$i; break; }
    }
  }
  if(trader=="") trader="UNKNOWN";
  cnt=$(NF);
  if(cnt+0==0) cnt=1;
  key=action"\t"trader;
  sums[key]+=cnt;
  counts[key]++;
}
END{
  for(k in sums) print k"\t"sums[k];
}' /usr/stock.log | sort -t$'\t' -k1,1 -k3,3nr | awk -F"\t" '{
  if(cur!=$1){ if(cur!="") print ""; cur=$1; print "TOP for " toupper($1) ":" }
  print $2"\t"$3
}'
"}
